changeURL().code:
function changeURL()
{
	var d = document.getElementById("linkURL");
	var defaultCountry = "";

	if(defaultCountry == 'spanish'){
		d.href = "http://www.dlinkla.com/soporte";
	}
	else if(defaultCountry == 'zhtw'){
		d.href = "http://www.dlinktw.com.tw/support";
	}
	else if(defaultCountry == 'portuguese'){
		d.href = "http://www.dlink.com.br/suporte";
	}
	else if(defaultCountry == 'zhcn'){
		d.href = "http://www.dlink.com.cn/support";
	}
}
